'use client'
import { useSignal, useSignals, cn } from '@cascivo/core'
import { useRef } from 'react'
import type { HTMLAttributes } from 'react'
import { t, builtin } from '@cascivo/i18n'
import styles from './otp-input.module.css'

export interface OtpInputProps extends Omit<HTMLAttributes<HTMLDivElement>, 'onChange'> {
  length?: number
  value: string
  onValueChange: (v: string) => void
  disabled?: boolean
  type?: 'numeric' | 'alphanumeric'
}

export function OtpInput({
  length = 6,
  value,
  onValueChange,
  disabled = false,
  type = 'numeric',
  className,
  ...props
}: OtpInputProps) {
  useSignals()
  const slots = useSignal<string[]>(Array.from({ length }, (_, i) => value[i] ?? ''))
  const inputRefs = useRef<Array<HTMLInputElement | null>>([])

  // Sync controlled value into slots during render
  const newSlots = Array.from({ length }, (_, i) => value[i] ?? '')
  if (JSON.stringify(slots.value) !== JSON.stringify(newSlots)) {
    slots.value = newSlots
  }

  function notifyChange(updatedSlots: string[]) {
    onValueChange(updatedSlots.join(''))
    slots.value = updatedSlots
  }

  function focusSlot(index: number) {
    const clamped = Math.max(0, Math.min(length - 1, index))
    inputRefs.current[clamped]?.focus()
  }

  function handleInput(index: number, char: string) {
    const pattern = type === 'numeric' ? /^\d$/ : /^[a-zA-Z0-9]$/
    if (!pattern.test(char)) return
    const updated = [...slots.value]
    updated[index] = char
    notifyChange(updated)
    if (index < length - 1) focusSlot(index + 1)
  }

  function handleKeyDown(index: number, e: React.KeyboardEvent<HTMLInputElement>) {
    if (e.key === 'Backspace') {
      e.preventDefault()
      const updated = [...slots.value]
      if (updated[index]) {
        updated[index] = ''
        notifyChange(updated)
      } else if (index > 0) {
        updated[index - 1] = ''
        notifyChange(updated)
        focusSlot(index - 1)
      }
    } else if (e.key === 'ArrowLeft') {
      e.preventDefault()
      focusSlot(index - 1)
    } else if (e.key === 'ArrowRight') {
      e.preventDefault()
      focusSlot(index + 1)
    }
  }

  function handlePaste(index: number, e: React.ClipboardEvent) {
    const pasted = e.clipboardData
      .getData('text')
      .replace(/\s/g, '')
      .slice(0, length - index)
    const pattern = type === 'numeric' ? /^\d+$/ : /^[a-zA-Z0-9]+$/
    // Only intercept when there is valid content to distribute. Leaving empty
    // or invalid pastes to the default action keeps the field paste-friendly
    // (and avoids tripping the "prevents pasting" best-practices audit).
    if (!pattern.test(pasted)) return
    e.preventDefault()
    const updated = [...slots.value]
    for (let i = 0; i < pasted.length; i++) {
      if (index + i < length) updated[index + i] = pasted[i] ?? ''
    }
    notifyChange(updated)
    focusSlot(Math.min(index + pasted.length, length - 1))
  }

  const ariaLabel = t(builtin.otpInput.label)

  return (
    <div
      className={cn(styles['wrapper'], className)}
      role="group"
      aria-label={ariaLabel}
      {...props}
    >
      {slots.value.map((slot, i) => (
        <input
          key={i}
          ref={(el) => {
            inputRefs.current[i] = el
          }}
          type={type === 'numeric' ? 'tel' : 'text'}
          inputMode={type === 'numeric' ? 'numeric' : 'text'}
          className={styles['slot']}
          value={slot}
          maxLength={1}
          aria-label={t(builtin.otpInput.digit, { n: String(i + 1) })}
          autoComplete={i === 0 ? 'one-time-code' : 'off'}
          disabled={disabled}
          data-filled={slot ? '' : undefined}
          onChange={(e) => {
            const val = e.currentTarget.value.slice(-1)
            if (val) handleInput(i, val)
          }}
          onKeyDown={(e) => handleKeyDown(i, e)}
          onPaste={(e) => handlePaste(i, e)}
          onFocus={(e) => e.currentTarget.select()}
        />
      ))}
    </div>
  )
}

@layer cascivo.component {
  .wrapper {
    display: flex;
    gap: var(--cascivo-space-2);
    align-items: center;
  }

  .slot {
    width: 2.75rem;
    height: 3rem;
    font-family: var(--cascivo-font-mono, var(--cascivo-font-sans));
    font-size: var(--cascivo-text-xl);
    font-weight: var(--cascivo-font-semibold);
    text-align: center;
    color: var(--cascivo-color-text);
    background-color: var(--cascivo-color-surface);
    border: 1.5px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-field);
    transition:
      border-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      box-shadow var(--cascivo-duration-150) var(--cascivo-ease-out);
    outline: none;
    caret-color: transparent;

    &:hover:not(:disabled) {
      border-color: var(--cascivo-color-border-strong);
    }

    &:focus {
      border-color: var(--cascivo-color-accent);
      box-shadow: var(--cascivo-focus-ring);
    }

    &[data-filled] {
      border-color: var(--cascivo-color-border-strong);
      background-color: var(--cascivo-color-bg-subtle);
    }

    &:disabled {
      opacity: 0.5;
      cursor: not-allowed;
    }
  }
}
